#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

#define MAX_SIZE 100

/* ---------- Stack Structure for Operators ---------- */
typedef struct {
 char items[MAX_SIZE];
 int top;
} OperatorStack;

void initOperatorStack(OperatorStack *s) {
 s->top = -1;
}

int isOperatorStackEmpty(OperatorStack *s) {
 return s->top == -1;
}

int isOperatorStackFull(OperatorStack *s) {
 return s->top == MAX_SIZE - 1;
}

void pushOperator(OperatorStack *s, char item) {
 if (!isOperatorStackFull(s)) {
 s->items[++s->top] = item;
 }
}

char popOperator(OperatorStack *s) {
 if (!isOperatorStackEmpty(s)) {
 return s->items[s->top--];
 }
 return '\0';
}

char peekOperator(OperatorStack *s) {
 if (!isOperatorStackEmpty(s)) {
 return s->items[s->top];
 }
 return '\0';
}

/* ---------- Stack Structure for Operands (integers) ---------- */
typedef struct {
 int items[MAX_SIZE];
 int top;
} OperandStack;

void initOperandStack(OperandStack *s) {
 s->top = -1;
}

int isOperandStackEmpty(OperandStack *s) {
 return s->top == -1;
}

int isOperandStackFull(OperandStack *s) {
 return s->top == MAX_SIZE - 1;
}

void pushOperand(OperandStack *s, int item) {
 if (!isOperandStackFull(s)) {
 s->items[++s->top] = item;
 }
}

int popOperand(OperandStack *s) {
 if (!isOperandStackEmpty(s)) {
 return s->items[s->top--];
 }
 return 0; // Default return for empty stack
}

/* ---------- Precedence and Associativity Functions ---------- */
int getPrecedence(char op) {
 switch (op) {
 case '^': return 3;
 case '*': 
 case '/': 
 case '%': return 2;
 case '+': 
 case '-': return 1;
 default: return 0;
 }
}

int isRightAssociative(char op) {
 return op == '^';
}

int isOperator(char c) {
 return c == '+' || c == '-' || c == '*' || 
 c == '/' || c == '%' || c == '^';
}

int isOperand(char c) {
 return isalnum(c); // Letter or digit
}

/* ---------- Infix to Postfix Conversion ---------- */
void infixToPostfix(const char *infix, char *postfix) {
 OperatorStack s;
 initOperatorStack(&s);

 char output[MAX_SIZE] = "";
 char temp[4];

 int i = 0, j = 0;
 char token;

 while (infix[i] != '\0') {
 token = infix[i];

 if (isOperand(token)) {
 // Operand: append directly to output
 temp[0] = token;
 temp[1] = ' ';
 temp[2] = '\0';
 strcat(output, temp);

 } else if (token == '(') {
 pushOperator(&s, token);

 } else if (token == ')') {
 // Pop until matching '('
 while (!isOperatorStackEmpty(&s) && peekOperator(&s) != '(') {
 temp[0] = popOperator(&s);
 temp[1] = ' ';
 temp[2] = '\0';
 strcat(output, temp);
 }
 popOperator(&s); // Discard the '('

 } else if (isOperator(token)) {
 // Handle operator precedence
 while (!isOperatorStackEmpty(&s) && 
 peekOperator(&s) != '(' &&
 (getPrecedence(peekOperator(&s)) > getPrecedence(token) ||
 (getPrecedence(peekOperator(&s)) == getPrecedence(token) &&
 !isRightAssociative(token)))) {
 temp[0] = popOperator(&s);
 temp[1] = ' ';
 temp[2] = '\0';
 strcat(output, temp);
 }
 pushOperator(&s, token);
 }
 i++;
 }

 // Pop remaining operators
 while (!isOperatorStackEmpty(&s)) {
 temp[0] = popOperator(&s);
 temp[1] = ' ';
 temp[2] = '\0';
 strcat(output, temp);
 }

 strcpy(postfix, output);
}

/* ---------- Postfix Evaluation ---------- */
int evaluatePostfix(const char *postfix) {
 OperandStack s;
 initOperandStack(&s);

 char token;
 int i = 0;
 int operand1, operand2, result;

 // Create a working copy
 char expr[MAX_SIZE];
 strcpy(expr, postfix);

 char *token_str = strtok(expr, " ");

 while (token_str != NULL) {
 char t = token_str[0];

 if (isdigit(t)) {
 // Push operand onto stack
 pushOperand(&s, atoi(token_str));

 } else if (isOperator(t)) {
 // Pop two operands: first is RIGHT, second is LEFT
 operand2 = popOperand(&s); // Right operand
 operand1 = popOperand(&s); // Left operand

 switch (t) {
 case '+': result = operand1 + operand2; break;
 case '-': result = operand1 - operand2; break;
 case '*': result = operand1 * operand2; break;
 case '/': result = operand1 / operand2; break;
 case '%': result = operand1 % operand2; break;
 case '^': result = 1;
 for (int j = 0; j < operand2; j++)
 result *= operand1;
 break;
 }
 pushOperand(&s, result);
 }

 token_str = strtok(NULL, " ");
 }

 return popOperand(&s);
}

/* ---------- Demonstration Function ---------- */
void demonstrateConversion(const char *infix) {
 char postfix[MAX_SIZE];

 printf("\nInfix Expression: %s\n", infix);
 infixToPostfix(infix, postfix);
 printf("Postfix Expression: %s\n", postfix);
}\n
void demonstrateEvaluation(const char *infix) {
 char postfix[MAX_SIZE];
 int result;

 printf("\nInfix Expression: %s\n", infix);
 infixToPostfix(infix, postfix);
 printf("Postfix Expression: %s\n", postfix);
 result = evaluatePostfix(postfix);
 printf("Evaluation Result: %d\n", result);
}

/* ---------- Main Function ---------- */
int main() {
 printf("============================================================\n");
 printf(" EXPRESSION EVALUATION AND CONVERSION IN C\n");
 printf("============================================================\n");

 // Example 1: A + B * C - D
 printf("\n*** Example 1: A + B * C - D ***");
 demonstrateConversion("A+B*C-D");
 // Verify with numbers: 2 + 3 * 4 - 5 = 2 + 12 - 5 = 9
 demonstrateEvaluation("2+3*4-5");

 // Example 2: (A + B) * (C - D)
 printf("\n*** Example 2: (A + B) * (C - D) ***");
 demonstrateConversion("(A+B)*(C-D)");
 // Verify with numbers: (2 + 3) * (7 - 4) = 5 * 3 = 15
 demonstrateEvaluation("(2+3)*(7-4)");

 // Example 3: A * (B + C) / D
 printf("\n*** Example 3: A * (B + C) / D ***");
 demonstrateConversion("A*(B+C)/D");
 // Verify with numbers: 10 * (2 + 3) / 5 = 50 / 5 = 10
 demonstrateEvaluation("10*(2+3)/5");

 // Example 4: Direct postfix evaluation
 printf("\n*** Example 4: Postfix Evaluation ***");
 printf("\nPostfix: 5 3 2 * + 4 -");
 int result = evaluatePostfix("5 3 2 * + 4 -");
 printf("\nResult: %d\n", result);
 printf("Verification: 5 + 3*2 - 4 = 5 + 6 - 4 = 7\n");

 printf("\n============================================================\n");
 printf(" TIME COMPLEXITY: O(n) for both conversion and evaluation\n");
 printf(" SPACE COMPLEXITY: O(n) for stack storage\n");
 printf("============================================================\n");

 return 0;
}
